 1	import {
 2	  MenuToggle,
 3	  MenuToggleElement,
 4	  Select,
 5	  SelectList,
 6	  SelectOption,
 7	} from '@patternfly/react-core';
 8	import * as React from 'react';
 9	import * as time from '../time';
10	
11	interface TimeUnitPickerProps {
12	  unit: time.Unit;
13	  onChange: (unit: time.Unit) => void;
14	}
15	
16	/** Pick a time unit (hours, days etc) */
17	export const TimeUnitPicker: React.FC<TimeUnitPickerProps> = ({ unit, onChange }) => {
18	  const [isOpen, setIsOpen] = React.useState(false);
19	
20	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
21	    <MenuToggle ref={toggleRef} onClick={() => setIsOpen(!isOpen)} isExpanded={isOpen}>
22	      {unit.name}
23	    </MenuToggle>
24	  );
25	
26	  return (
27	    <Select
28	      id={'unit-select'}
29	      selected={unit.name}
30	      isOpen={isOpen}
31	      onSelect={(_: React.MouseEvent, value: string) => {
32	        const newUnit = time.Unit.get(value);
33	        if (newUnit) onChange(newUnit);
34	        setIsOpen(false);
35	      }}
36	      onOpenChange={(isOpen: boolean) => setIsOpen(!isOpen)}
37	      toggle={toggle}
38	    >
39	      <SelectList>
40	        {time.Unit.all().map((u) => (
41	          <SelectOption key={u.name} value={u.name}>
42	            {' '}
43	            {u.name}{' '}
44	          </SelectOption>
45	        ))}
46	      </SelectList>
47	    </Select>
48	  );
49	};

